/* Enable common ligatures and old-style figures for body text */
.article-body {
  font-feature-settings: "liga" 1, "onum" 1;
  -webkit-font-feature-settings: "liga" 1, "onum" 1; /* For older WebKit compatibility */
}

/* Enable discretionary ligatures and small caps for headlines */
h1 {
  font-feature-settings: "dlig" 1, "smcp" 1;
  -webkit-font-feature-settings: "dlig" 1, "smcp" 1; /* For older WebKit compatibility */
  font-variant: small-caps; /* Fallback/helper for wider browser support */
}
